      const pdfBuffer = await generateInvoicePdf({ invoiceId });
      const filename = invoice.invoiceNumber ? `${invoice.invoiceNumber}.pdf` : `invoice-${invoiceId}.pdf`;
      res.setHeader("Content-Type", "application/pdf");
